
.status-card {
  width: 100%;
  max-width: 380px;
  margin: 0 auto;
  font-family: var(--font-mono);
  color: var(--c-text);
  font-size: 11px;
  line-height: 1.45;
  background: var(--c-surface);
  border: 1px solid var(--c-border);
  border-radius: 10px;
  overflow: hidden;
}

.time-section {
  padding: 12px 16px 8px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.time-value {
  font-weight: bold;
  font-size: 0.85rem;
  letter-spacing: 0.5px;
}

.stats-section {
  padding: 6px 16px 14px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.stat-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-header {
  display: flex;
  align-items: center;
  gap: 6px;
}

.stat-icon {
  font-size: 0.85rem;
  width: 16px;
  text-align: center;
}

.stat-name {
  font-weight: bold;
  font-size: 0.75rem;
  min-width: 36px;
  color: var(--c-text-dim);
}

.stat-num {
  font-weight: bold;
  font-size: 0.75rem;
  min-width: 24px;
  text-align: right;
}

.stat-tag {
  font-size: 0.6rem;
  font-weight: bold;
  padding: 1px 5px;
  border-radius: 3px;
  border: 1px solid;
  letter-spacing: 0.5px;

  &.high {
    color: var(--c-food-high);
    border-color: var(--c-food-high);
    background: rgba(78, 203, 113, 0.08);
  }

  &.mid {
    color: var(--c-food-mid);
    border-color: var(--c-food-mid);
    background: rgba(212, 168, 67, 0.08);
  }

  &.low {
    color: var(--c-food-low);
    border-color: var(--c-food-low);
    background: rgba(224, 85, 69, 0.08);
  }
}

.stat-bar {
  height: 4px;
  border-radius: 2px;
  background: var(--c-bg);
  overflow: hidden;
}

.stat-bar-inner {
  height: 100%;
  border-radius: 2px;
  transition: width 0.35s ease;

  &.high { background: var(--c-food-high); }
  &.mid  { background: var(--c-food-mid); }
  &.low  { background: var(--c-food-low); }
}

.stat-hint {
  font-size: 0.6rem;
  color: var(--c-text-dim);
  padding-left: 22px;
}

@media (max-width: 400px) {
  .status-card {
    max-width: 100%;
  }

  .stat-header {
    flex-wrap: wrap;
  }
}
